#include <cstdint>
#include <iostream>

int main()
{
    double d{};
    int n{};
    std::cin >> d >> n;

    int truncated{ static_cast<int>(d) };

    bool frac_positive{ d - static_cast<double>(truncated) > 0.0 };

    int signed_result{ truncated - n };

    uint32_t unsigned_result{ static_cast<uint32_t>(truncated) - static_cast<uint32_t>(n) };

    bool wrapped{ static_cast<int>(unsigned_result) != signed_result };

    std::cout << std::boolalpha;
    std::cout << "Truncated: " << truncated << '\n';
    std::cout << "Fractional part positive: " << frac_positive << '\n';
    std::cout << "Signed result: " << signed_result << '\n';
    std::cout << "Unsigned result: " << unsigned_result << '\n';
    std::cout << "Wrapped: " << wrapped << '\n';

